return ['domain'=>'return-requests-woo','plural-forms'=>'nplurals=3; plural=(n==1 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2);','language'=>'pl_PL','project-id-version'=>'Return Requests for WooCommerce 5.0.0','pot-creation-date'=>'2026-03-23T00:42:37+00:00','po-revision-date'=>'2026-03-23T00:42:37+00:00','messages'=>['&#9888; Administrator email is not configured. Return notifications will not be sent to the store admin. <a href="%s">Go to Email Settings</a>.'=>'&#9888; E-mail administratora nie jest skonfigurowany. Powiadomienia o zwrotach nie będą wysyłane do administratora sklepu. <a href="%s">Przejdź do Ustawień e-maili</a>.','&#9888; Required page "/%1$s/" does not exist. <a href="%2$s">Go to Pages tab</a> to recreate it.'=>'&#9888; Wymagana strona "/%1$s/" nie istnieje. <a href="%2$s">Przejdź do zakładki Strony</a>, aby ją odtworzyć.','(Recommended) Configure Cloudflare Turnstile as spam protection.'=>'(Zalecane) Skonfiguruj Cloudflare Turnstile jako ochronę przed spamem.','To access the return form, you must use the link from the verification email or the "Return Order" button in your customer dashboard.'=>'Aby uzyskać dostęp do formularza zwrotu, musisz użyć linku z maila weryfikacyjnego lub przycisku "Zwrot zamówienia" w panelu klienta.','Contact email address:'=>'Adres e-mail do kontaktu:','Sender address. It must be authenticated by your Mail/SMTP server to avoid spam filters.'=>'Adres wysyłający. Musi być autoryzowany przez Twój serwer poczty/SMTP, aby uniknąć filtrów spam.','Address:'=>'Adres:','I acknowledge that the refund will be processed exclusively to the provided bank account number.'=>'Akceptuję, że zwrot środków zostanie wykonany wyłącznie na podany przeze mnie numer konta bankowego.','Security'=>'Bezpieczeństwo','Access parameters missing'=>'Brak parametrów dostępu','Missing required contact details'=>'Brak wymaganych danych kontaktowych','Missing required contact details (phone number or address). Please update them in account settings.'=>'Brak wymaganych danych kontaktowych (nr telefonu lub adres). Uzupełnij je w ustawieniach konta.','Missing required data. Ensure products for return are selected and bank account number is provided.'=>'Brak wymaganych danych. Upewnij się, że wybrano produkty do zwrotu i podano numer konta bankowego.','Composer autoloader is missing. Run `composer install` in the plugin directory.'=>'Brakuje autoloadera Composer. Uruchom `composer install` w katalogu wtyczki.','Plugin configuration error. Please contact the administrator.'=>'Błąd konfiguracji wtyczki. Skontaktuj się z administratorem.','Order date verification error.'=>'Błąd weryfikacji daty zamówienia.','Form verification error. Please refresh the page and try again.'=>'Błąd weryfikacji formularza. Odśwież stronę i spróbuj ponownie.','Price'=>'Cena','Cloudflare Turnstile (SPAM Protection)'=>'Cloudflare Turnstile (Ochrona przed SPAMem)','PDF generation data:'=>'Dane do generowania PDF:','Return details:'=>'Dane do zwrotu:','Customer details:'=>'Dane klienta:','E-mail must match the order'=>'E-mail musi być taki sam jak w zamówieniu','Store details:'=>'Dane sklepu:','Order date:'=>'Data zamówienia:','Form submission date:'=>'Data złożenia formularza:','Only completed orders are eligible for return.'=>'Do zwrotu kwalifikują się wyłącznie zrealizowane zamówienia.','Customize email titles and content.'=>'Dostosuj tytuły i treści wiadomości e-mail.','Learn more about Cloudflare Turnstile'=>'Dowiedz się więcej o Cloudflare Turnstile','Thank you for using our services.'=>'Dziękujemy za skorzystanie z naszych usług.','Administrator email:'=>'E-mail administratora:','Email for administrator'=>'E-mail dla administratora','Email for customer'=>'E-mail dla klienta','Sender email:'=>'E-mail nadawcy:','Email:'=>'E-mail:','Bank account number format:'=>'Format numeru konta bankowego:','Return Form'=>'Formularz Zwrotu','Product Selection Form for Return'=>'Formularz wyboru produktów do zwrotu','IBAN (International)'=>'IBAN (międzynarodowy)','Quantity'=>'Ilość','Quantity:'=>'Ilość:','First and Last Name:'=>'Imię i nazwisko:','Information'=>'Informacje','Please be informed that personal data processing complies with GDPR regulations and is based on'=>'Informujemy, że przetwarzanie danych osobowych odbywa się zgodnie z przepisami RODO oraz na podstawie','If you didn\'t request an order return, please ignore this message.'=>'Jeśli nie prosiłeś o zwrot zamówienia, zignoruj tę wiadomość.','If the button does not work, copy and paste the following link into your browser:'=>'Jeśli przycisk nie działa, skopiuj i wklej poniższy link do przeglądarki:','Delete returns'=>'Kasowanie zwrotów','By clicking "Return selected items", I declare that I have read the'=>'Klikając przycisk "Zwróć wybrane przedmioty", oświadczam, że zapoznałem/am się z','Click the button below to check if required pages exist and recreate them if necessary.'=>'Kliknij poniższy przycisk, aby sprawdzić czy wymagane strony istnieją i ewentualnie je utworzyć.','Verification link has expired or is invalid'=>'Link weryfikacyjny wygasł lub jest nieprawidłowy','No.'=>'Lp.','The statutory return period for this order has expired.'=>'Minął regulaminowy czas na zwrot tego zamówienia.','You must type "confirm" to delete all records.'=>'Musisz wpisać "potwierdzam", aby usunąć wszystkie rekordy.','Email sender name:'=>'Nazwa nadawcy e-maili:','Display name in email client (e.g. "My Store Returns").'=>'Nazwa wyświetlana w kliencie pocztowym (np. "Mój Sklep Zwroty").','Could not find an order with the provided number. Please check your order number.'=>'Nie udało się znaleźć zamówienia o podanym numerze. Sprawdź czy podałeś prawidłowy numer zamówienia.','Order not found'=>'Nie znaleziono zamówienia','Unauthorized operation. Product identity verification failed.'=>'Niedozwolona operacja. Błąd weryfikacji tożsamości produktów.','Invalid bank account number format. Number must contain 26 digits.'=>'Nieprawidłowy format numeru konta bankowego. Numer musi zawierać 26 cyfr.','Invalid return token or session expired.'=>'Nieprawidłowy token zwrotu lub sesja wygasła.','New return for order #{order_id}'=>'Nowy zwrot zamówienia #{order_id}','Bank account number:'=>'Numer konta bankowego:','Account number must contain exactly 26 digits!'=>'Numer konta powinien zawierać dokładnie 26 cyfr!','Order number:'=>'Numer zamówienia:','Return time window (days):'=>'Okno czasowe zwrotu (dni):','Defines how the bank account number provided by the customer is verified.'=>'Określa, jak weryfikowany jest numer konta bankowego podany przez klienta.','Plugin operation description'=>'Opis działania wtyczki','Empty returns list'=>'Opróżnij listę zwrotów','We received a return request for your order. To continue the process, please verify your request by clicking the button below:'=>'Otrzymaliśmy prośbę o zwrot zamówienia. Aby kontynuować proces, prosimy o weryfikację tej prośby klikając poniższy przycisk:','I declare that pursuant to Art. 27 of the Consumer Rights Act of May 30, 2014, I am returning the purchased goods. I declare that returned goods are unused and in unaltered condition.'=>'Oświadczam, że zgodnie z art. 27 ustawy z dnia 30 maja 2014 o prawach konsumenta zwracam zakupiony towar. Oświadczam, że zwracany towar jest w stanie niezmienionym i nie był używany.','I declare that I am familiar with the return conditions specified in the Terms and Conditions and accept the Privacy Policy.'=>'Oświadczam, że znane są mi warunki zwrotów określone w regulaminie oraz akceptuję politykę prywatności sklepu.','Enter administrator email'=>'Podaj e-mail administratora','Enter sender email'=>'Podaj e-mail nadawcy','Enter bank account number for refund:'=>'Podaj numer konta bankowego do zwrotu:','Provided details do not match the order details.'=>'Podane dane nie są zgodne z danymi zamówienia.','Customer signature:'=>'Podpis klienta:','Shown to customers in the return form as a contact address.'=>'Pokazywany klientom w treści formularza zwrotu jako adres kontaktowy.','Privacy policy'=>'Polityką prywatności','Polish (26 digits)'=>'Polski (26 cyfr)','Required plugins'=>'Potrzebne wtyczki do działania','I confirm the return'=>'Potwierdzam zwrot','Product'=>'Produkt','Products to return:'=>'Produkty do zwrotu:','Goods Return Protocol'=>'Protokół zwrotu towaru','Go to %1$sEmail Settings%2$s and set the administrator email.'=>'Przejdź do %1$sUstawień e-maili%2$s i ustaw adres e-mail administratora.','Go to return form'=>'Przejdź do formularza zwrotu','Token verification attempts limit exceeded. Please try again in an hour or contact store support.'=>'Przekroczono limit prób weryfikacji tokenu. Spróbuj ponownie za godzinę lub skontaktuj się z obsługą sklepu.','Verification attempts limit exceeded. Please try again in an hour.'=>'Przekroczono limit prób weryfikacji. Spróbuj ponownie za godzinę.','Terms and Conditions'=>'Regulaminem','Records older than a year have been deleted.'=>'Rekordy starsze niż rok zostały usunięte.','I understand, close'=>'Rozumiem, zamknij','Secret Key:'=>'Secret Key:','Session expired or invalid'=>'Sesja wygasła lub jest nieprawidłowa','Site Key:'=>'Site Key:','Return form slug:'=>'Slug formularza zwrotu:','Return confirmation slug:'=>'Slug potwierdzenia zwrotu:','Item selection slug:'=>'Slug wyboru przedmiotów:','Check and create required pages'=>'Sprawdź i utwórz wymagane strony','Try again'=>'Spróbuj ponownie','Try again or contact store support.'=>'Spróbuj ponownie lub skontaktuj się z obsługą sklepu.','Try again.'=>'Spróbuj ponownie.','Pages'=>'Strony','Detailed information can be found in the attached PDF file.'=>'Szczegółowe informacje znajdziesz w załączonym pliku PDF.','This message was generated automatically. Please do not reply.'=>'Ta wiadomość została wygenerowana automatycznie. Prosimy nie odpowiadać na nią.','This plugin enables return management in WooCommerce.'=>'Ta wtyczka umożliwia zarządzanie zwrotami w WooCommerce.','Phone:'=>'Telefon:','This address receives a copy of every return request with an attached PDF.'=>'Ten adres otrzymuje kopię każdego wniosku o zwrot z załączonym PDF-em.','Content:'=>'Treść:','Your session may have expired or the link format is invalid. Please try again.'=>'Twoja sesja mogła wygasnąć lub link ma nieprawidłowy format. Spróbuj ponownie.','Your return for order #{order_id} has been registered.'=>'Twój zwrot zamówienia #{order_id} został zarejestrowany.','Email title for administrator'=>'Tytuł wiadomości dla administratora','Email title for customer'=>'Tytuł wiadomości dla klienta','Title:'=>'Tytuł:','URL slug for page with [return_form] shortcode. Default: return-form'=>'URL slug strony z shortcode [return_form]. Domyślnie: formularz-zwrotu','URL slug for page with [return_items_form] shortcode. Default: select-return-items'=>'URL slug strony z shortcode [return_items_form]. Domyślnie: wybierz-przedmioty-do-zwrotu','URL slug for page with [return_confirmation] shortcode. Default: return-confirmed'=>'URL slug strony z shortcode [return_confirmation]. Domyślnie: zwrot-potwierdzony','Settings'=>'Ustawienia','Cloudflare Turnstile settings saved.'=>'Ustawienia Cloudflare Turnstile zostały zapisane.','Email settings'=>'Ustawienia e-maili','Email settings saved.'=>'Ustawienia e-maili zostały zapisane.','Plugin pages settings'=>'Ustawienia stron wtyczki','Pages settings saved.'=>'Ustawienia stron zostały zapisane.','Deletes all return records older than a year.'=>'Usunie wszystkie rekordy zwrotów starsze niż rok.','Deletes all return records from the database.'=>'Usunie wszystkie rekordy zwrotów z bazy danych.','Delete records older than a year'=>'Usuń rekordy starsze niż rok','Delete old returns'=>'Usuń stare zwroty','Delete all returns'=>'Usuń wszystkie zwroty','The following pages were created: %s.'=>'Utworzono następujące strony: %s.','Create required pages'=>'Utwórz wymagane strony','Warning: Deleted data cannot be restored.'=>'Uwaga: Usunięte dane nie będą mogły zostać przywrócone.','Use {order_id} as a placeholder for order number.'=>'Użyj {order_id} jako symbolu zastępczego numeru zamówienia.','For security purposes, verification links are one-time use and expire one hour after generation.'=>'W celach bezpieczeństwa, linki weryfikacyjne są jednorazowe i wygasają po godzinie od wygenerowania.','If you have any questions or concerns regarding the return, please contact our customer service at'=>'W przypadku jakichkolwiek pytań lub wątpliwości dotyczących zwrotu prosimy o kontakt z naszym działem obsługi klienta pod adresem','Verification - Order return #%d'=>'Weryfikacja - Zwrot zamówienia #%d','Turnstile verification failed. Please refresh the page and try again.'=>'Weryfikacja Turnstile nie powiodła się. Prosimy odświeżyć stronę i spróbować ponownie.','Type "confirm"'=>'Wpisz "potwierdzam"','Specify the page slugs used by the plugin. Do not change shortcodes on these pages.'=>'Wskaż slugi stron używanych przez wtyczkę. Nie zmieniaj shortcode na tych stronach.','All rights reserved.'=>'Wszelkie prawa zastrzeżone.','All records have been deleted.'=>'Wszystkie rekordy zostały usunięte.','All required pages already exist.'=>'Wszystkie wymagane strony już istnieją.','All returns'=>'Wszystkie zwroty','Return Requests for WooCommerce plugin is active!'=>'Wtyczka Return Requests for WooCommerce jest aktywna!','Select products to return:'=>'Wybierz produkty do zwrotu:','Generate new link'=>'Wygeneruj nowy link','Required pages were created automatically. Configure the plugin in a few steps:'=>'Wymagane strony zostały utworzone automatycznie. Dokonfiguruj wtyczkę w kilku krokach:','An error occurred while processing the return:'=>'Wystąpił błąd podczas przetwarzania zwrotu:','A problem occurred while sending the email. Please try again later.'=>'Wystąpił problem podczas wysyłania maila. Spróbuj ponownie później.','Verification email sent successfully. Please check your inbox.'=>'Wysłanie maila weryfikacyjnego powiodło się. Sprawdź skrzynkę mailową.','Disabled (no validation)'=>'Wyłączona (brak walidacji)','Send verification link'=>'Wyślij link weryfikacyjny','Enable Turnstile'=>'Włącz Turnstile','Order does not meet return conditions or was manipulated.'=>'Zamówienie nie spełnia warunków zwrotu lub padło ofiarą manipulacji.','Save settings'=>'Zapisz ustawienia','Save Turnstile settings'=>'Zapisz ustawienia Turnstile','Save pages settings'=>'Zapisz ustawienia stron','Data management'=>'Zarządzanie danymi','Submit return'=>'Zgłoś zwrot','Return'=>'Zwrot','Return for this order has already been registered.'=>'Zwrot dla tego zamówienia został już zarejestrowany.','Return for this order has already been registered. If you have any questions, please contact customer service.'=>'Zwrot dla tego zamówienia został już zarejestrowany. Jeśli masz pytania, skontaktuj się z obsługą klienta.','Return already registered'=>'Zwrot już zarejestrowany','Order return'=>'Zwrot zamówienia','Return for order #{order_id}'=>'Zwrot zamówienia #{order_id}','Return for order #{order_id} has been submitted.'=>'Zwrot zamówienia #{order_id} został zgłoszony.','Return registered'=>'Zwrot został zarejestrowany','Return selected items'=>'Zwróć wybrane przedmioty','e.g. Store Name&#10;Street 123&#10;00-000 City&#10;Phone number'=>'np. Nazwa sklepu&#10;Ulica 123&#10;00-000 Miasto&#10;Numer telefonu','e.g. contact@yourdomain.com'=>'np. kontakt@twojadomena.pl','and'=>'oraz','and accept their provisions. I also commit to returning the selected products at my own expense, under Art. 27 of the Consumer Rights Act of May 30, 2014.'=>'sklepu i akceptuję ich postanowienia. Zobowiązuję się również do zwrotu wybranych produktów na własny koszt, zgodnie z art. 27 ustawy z dnia 30 maja 2014 r. o prawach konsumenta.','The "Return Requests WooCommerce" plugin allows customers to submit order return requests in the online store. Guest users can use a form followed by email verification, while logged-in customers can submit returns directly from the "My Account" panel. The plugin generates a PDF file with return information and emails it to both the store administrator and the customer. Optional Cloudflare Turnstile protection is implemented to prevent SPAM.'=>'Wtyczka "Zwroty WooCommerce" pozwala klientom zgłaszać zwroty zamówień w sklepie internetowym. Niezalogowani użytkownicy mogą skorzystać z formularza, a następnie z weryfikacji mailowej, zalogowani klienci mają możliwość zgłoszenia zwrotu bezpośrednio z panelu "Moje konto". Wtyczka generuje plik PDF z informacjami o zwrocie i wysyła go na e-mail zarówno do administratora sklepu, jak i klienta. Opcjonalnie zaimplementowano ochronę Cloudflare Turnstile w celu zapobiegania SPAMowi.','Required for managing orders and customers.'=>'Wymagane do zarządzania zamówieniami i klientami.','e.g. Company / Name'=>'np. Nazwa firmy / Imię i Nazwisko','Return Requests for WooCommerce'=>'Return Requests for WooCommerce','ID'=>'ID','Order'=>'Zamówienie','Customer'=>'Klient','Bank account'=>'Konto bankowe','Date'=>'Data','Actions'=>'Akcje','Details'=>'Szczegóły','No returns.'=>'Brak zwrotów.','Return Requests'=>'Return Requests','How does it work?'=>'Jak to działa?','This plugin provides a comprehensive native return management workflow for WooCommerce, securely handling returns from both authenticated users and guests.'=>'Ta wtyczka zapewnia kompleksowy, natywny obieg zgłaszania zwrotów dla WooCommerce, bezpiecznie obsługując zgłoszenia zarówno od zalogowanych użytkowników, jak i gości.','1. Initialization and Automated Pages'=>'1. Inicjalizacja i Automatyczne Strony','By clicking "Check and Create Required Pages" in the Pages tab, three routing pages are created using shortcodes:'=>'Po kliknięciu "Utwórz wymagane strony" w zakładce Strony, tworzone są trzy strony oparte na shortcode\'ach:','Entry point for guest users.'=>'Punkt wejścia dla niezalogowanych użytkowników (gości).','Select Return Items'=>'Wybierz przedmioty do zwrotu','Secure session-gated page where customers select products and input their bank account.'=>'Zabezpieczona sesją strona, na której klienci wybierają produkty i podają numer konta bankowego.','Return Confirmation'=>'Potwierdzenie zwrotu','Success page displaying the generated PDF file link.'=>'Strona sukcesu wyświetlająca link do wygenerowanego pliku PDF.','2. The Flow for Logged-In Customers'=>'2. Proces dla zalogowanych klientów','A logged-in user visits their "My Account" dashboard and navigates to "Orders".'=>'Zalogowany użytkownik wchodzi do swojego panelu "Moje konto" i przechodzi do zakładki "Zamówienia".','If an order has the status "Completed" and falls within the statutory return window, a "Return" button natively appears next to the order.'=>'Jeśli zamówienie ma status "Zrealizowane" i mieści się w ustawowym oknie czasowym na zwrot, obok zamówienia pojawia się przycisk "Zwrot".','Once clicked, the plugin generates a secure session token directly on the server without needing an email verification step (since the user identity is already verified by WordPress).'=>'Po kliknięciu wtyczka generuje bezpieczny token sesji bezpośrednio na serwerze bez konieczności weryfikacji e-mailowej (ponieważ tożsamość użytkownika jest już potwierdzona przez WordPress).','The user is instantly redirected to the Select Return Items page with their authenticated session active.'=>'Użytkownik jest natychmiast przekierowywany na stronę Wyboru Przedmiotów do Zwrotu z aktywną autoryzowaną sesją.','3. The Flow for Guest Customers (Unregistered)'=>'3. Proces dla klientów niezalogowanych (Gości)','A guest user visits the Return Form page.'=>'Niezalogowany użytkownik wchodzi na stronę Formularza Zwrotu.','They input their Order Number and the Billing Email Address associated with that order.'=>'Podaje Numer Zamówienia oraz Adres E-mail Płatnika przypisany do tego zamówienia.','The plugin cross-references the database and generates a cryptographically secure 1-hour Return Token tying their request to that specific order.'=>'Wtyczka sprawdza bazę danych i generuje kryptograficznie bezpieczny, ważny 1 godzinę Token Zwrotu, wiążąc żądanie z tym konkretnym zamówieniem.','An automated email is dispatched to the user containing a one-time verification link.'=>'Do użytkownika wysyłany jest automatyczny e-mail zawierający jednorazowy link weryfikacyjny.','Upon clicking the link, the user\'s browser establishes an authenticated system session using the token, proving they own the email address. They are then securely redirected to the Select Return Items page.'=>'Po kliknięciu w link, przeglądarka użytkownika nawiązuje autoryzowaną sesję używając tokena, co potwierdza, że jest on właścicielem adresu e-mail. Następnie jest on bezpiecznie przekierowywany na stronę Wyboru Przedmiotów do Zwrotu.','4. Form Submission and PDF Generation'=>'4. Wysłanie formularza i Generowanie PDF','Once the user reaches the Select Return Items page, they select the exact items they wish to return and input their bank account number.'=>'Gdy użytkownik znajdzie się na stronie Wyboru Przedmiotów do Zwrotu, wybiera konkretne przedmioty, które chce zwrócić, i podaje numer konta bankowego.','Optionally, a Cloudflare Turnstile gateway protects the form from automated abuse.'=>'Opcjonalnie, formularz jest chroniony przed automatycznym spamem za pomocą zabezpieczenia Cloudflare Turnstile.','Upon clicking "Return Selected Items", the request is officially recorded in the custom database table.'=>'Po kliknięciu "Zwróć wybrane przedmioty", żądanie zostaje oficjalnie zarejestrowane w dedykowanej tabeli w bazie danych.','The generative engine constructs a Goods Return Protocol PDF, filling it automatically with the store\'s details, the customer\'s billing address, and a compliance declaration.'=>'Silnik generujący tworzy plik PDF z Protokołem Zwrotu Towaru, automatycznie uzupełniając go danymi sklepu, adresem płatnika i deklaracją zgodności.','The PDF is saved securely to the server.'=>'Plik PDF jest bezpiecznie zapisywany na serwerze.','Two automated emails are dispatched: A confirmation to the Customer including the attached PDF, and a notification to the Administrator containing the same attached PDF.'=>'Wysyłane są dwa automatyczne e-maile: Potwierdzenie do klienta wraz z załączonym PDF oraz powiadomienie do administratora zawierające ten sam załącznik.','The customer\'s secure session is flushed and they land on the final Confirmation page.'=>'Bezpieczna sesja klienta zostaje zakończona, a on trafia na ostateczną stronę Potwierdzenia.','5. Email Notifications Overview'=>'5. Przegląd powiadomień E-mail','Verification Email (Guest only):'=>'E-mail weryfikacyjny (Tylko dla gości):','Sent immediately after a guest submits the initial Return Form to verify their identity via a secure link. E-mail in form needs to match order billing e-mail.'=>'Wysyłany natychmiast po wysłaniu przez gościa wstępnego Formularza Zwrotu, aby zweryfikować jego tożsamość poprzez bezpieczny link. E-mail w formularzu musi być zgodny z e-mailem rozliczeniowym na zamówieniu.','Customer Confirmation:'=>'Potwierdzenie dla klienta:','Sent after successfully selecting items and generating the Return Protocol PDF. Contains the PDF as an attachment.'=>'Wysyłany po pomyślnym wybraniu przedmiotów i wygenerowaniu Protokołu Zwrotu PDF. Zawiera wygenerowany plik PDF jako załącznik.','Administrator Notification:'=>'Powiadomienie dla administratora:','Sent simultaneously to the store owner alerting them of the return, with the Return Protocol PDF attached.'=>'Wysyłane równocześnie do właściciela sklepu informujące o zwrocie, z załączonym Protokołem Zwrotu PDF.','Support Return Requests'=>'Wesprzyj Return Requests','I created Return Requests to give the WordPress community a truly free, native, and bloat-free return management solution. If this plugin saves you time or money, please consider buying me a coffee! It directly helps me maintain the project and develop new features.'=>'Stworzyłem Return Requests, aby dać społeczności WordPressa w pełni darmowe, natywne i bezpieczne rozwiązanie do zarządzania zwrotami. Jeśli ta wtyczka oszczędza Twój czas lub pieniądze, rozważ postawienie mi kawy! Pomaga mi to bezpośrednio w utrzymaniu projektu i rozwijaniu nowych funkcji.','Buy me a coffee'=>'Postaw mi kawę','Comprehensive return management system for WooCommerce. Registers return requests, allows customers to select products and generates PDF with details.'=>'Kompleksowy system zarządzania zwrotami dla WooCommerce. Rejestruje wnioski o zwrot, umożliwia klientom wybór produktów i generuje pliki PDF ze szczegółami.','Number of days from the date the order was completed within which the customer can submit a return request. Default: 14 days.'=>'Liczba dni od daty zrealizowania zamówienia, w ciągu których klient może złożyć wniosek o zwrot. Domyślnie: 14 dni.','Unauthorized access.'=>'Nieautoryzowany dostęp.','Security check failed.'=>'Błąd weryfikacji bezpieczeństwa.','File not found on server.'=>'Nie znaleziono pliku na serwerze.','Return System Status'=>'Status systemu zwrotów','Active'=>'Aktywny','Disabled'=>'Wyłączony','When disabled, frontend return forms will be visually disabled, the My Account return button will vanish, and backend processing will be entirely rejected. Existing shortcodes will still render.'=>'Gdy ta opcja jest wyłączona, przycisk zwrotu w zakładce Moje Konto zostanie ukryty, formularze zwrotu będą wizualnie wyłączone, a wszystkie żądania backendowe zostaną odrzucone. Strony z przypisanymi shortcode\'ami będą nadal działać i informować o wyłączonym systemie.','The return system is currently disabled. Please try again later or contact support.'=>'System zwrotów jest obecnie wyłączony. Spróbuj ponownie później lub skontaktuj się z obsługą sklepu.','Missing required contact details: address.'=>'Brak wymaganych danych kontaktowych: adres.','Missing required contact details (address). Please update them in account settings.'=>'Brak wymaganych danych kontaktowych (adres). Uzupełnij je w ustawieniach konta.','Enter bank account number'=>'Wpisz numer konta bankowego','Please enter your valid bank account number'=>'Wpisz swój poprawny numer konta bankowego','Invalid IBAN format. Please check your international bank account number.'=>'Nieprawidłowy format IBAN. Sprawdź swój międzynarodowy numer konta bankowego.','Bank account number cannot be empty.'=>'Numer konta bankowego nie może być pusty.','PL12 3456 7890 1234 5678 9012 3456'=>'PL12 3456 7890 1234 5678 9012 3456','Account number should contain country code and up to 32 alphanumeric characters'=>'Numer konta powinien zawierać kod kraju i do 32 znaków alfanumerycznych','12 3456 7890 1234 5678 9012 3456'=>'12 3456 7890 1234 5678 9012 3456','Account number should contain exactly 26 digits'=>'Numer konta powinien zawierać dokładnie 26 cyfr','Return Confirmation Settings saved.'=>'Ustawienia Potwierdzenia Zwrotu zostały zapisane.','Return Confirmation Page Settings'=>'Ustawienia strony Potwierdzenia Zwrotu','Configure the company address shown on the Return Confirmation page ([return_confirmation] shortcode). After submitting a return, customers are directed here and shown where to send their package.'=>'Skonfiguruj adres firmy wyświetlany na stronie Potwierdzenia Zwrotu (shortcode [return_confirmation]). Po złożeniu zwrotu klienci są tu kierowani i informowani, gdzie nadać paczkę.','Company / Store name:'=>'Nazwa firmy / Sklepu:','Street and number:'=>'Ulica i numer:','Postal code and city:'=>'Kod pocztowy i miasto:','Country:'=>'Kraj:','Additional instructions:'=>'Dodatkowe instrukcje:','Optional extra message shown below the address (e.g. packaging instructions).'=>'Opcjonalna dodatkowa wiadomość wyświetlana pod adresem (np. instrukcje pakowania).','Save Return Confirmation settings'=>'Zapisz ustawienia Potwierdzenia Zwrotu','Preview — [return_confirmation] shortcode'=>'Podgląd — shortcode [return_confirmation]','This is how the Return Confirmation page looks in the admin context (without a real return token). The actual page shown to customers will include their order details.'=>'Tak wygląda strona Potwierdzenia Zwrotu w kontekście panelu administracyjnego (bez prawdziwego tokenu zwrotu). Strona realna widoczna dla klientów będzie zawierała dane ich zamówienia.','e.g. My Store Sp. z o.o.'=>'np. Mój Sklep Sp. z o.o.','e.g. ul. Kwiatowa 12'=>'np. ul. Kwiatowa 12','e.g. 00-001 Warszawa'=>'np. 00-001 Warszawa','e.g. Poland'=>'np. Polska','e.g. Please mark the package as RETURN'=>'np. Proszę oznacz paczkę jako ZWROT','Return Confirmation — live preview'=>'Potwierdzenie Zwrotu — podgląd na żywo','On the frontend, this page displays the return summary and the address below after a return is successfully submitted.'=>'Na stronie publicznej ta strona wyświetla podsumowanie zwrotu i adres poniżej po pomyślnym złożeniu zwrotu.','Send your package to:'=>'Wyślij paczkę na adres:','Return confirmation not found or the link has expired.'=>'Potwierdzenie zwrotu nie zostało znalezione lub link wygasł.','Start a new return.'=>'Rozpocznij nowy zwrot.','Order not found.'=>'Nie znaleziono zamówienia.','Return registered successfully'=>'Zwrot został zarejestrowany pomyślnie','Order summary'=>'Podsumowanie zamówienia','Customer:'=>'Klient:','Back to My Account'=>'Wróć do Mojego Konta','Plugin pages &amp; shortcodes'=>'Strony wtyczki i shortcody','The plugin uses three pages with dedicated shortcodes. Use "Check and Create Required Pages" in the Pages tab to create them automatically, or place the shortcodes manually on any page.'=>'Wtyczka używa trzech stron z dedykowanymi shortcode\'ami. Użyj opcji "Sprawdź i utwórz wymagane strony" w zakładce Strony, aby je automatycznie utworzyć, lub umieść shortcode\'y ręcznie na dowolnej stronie.','Entry point for guests. Customers enter their order number and billing email to receive a one-time verification link.'=>'Punkt wejścia dla gości. Klienci wpisują numer zamówienia i e-mail płatnika, aby otrzymać jednorazowy link weryfikacyjny.','Secure session-gated page where customers select products to return and provide their bank account number. Requires a valid session or verification token.'=>'Zabezpieczona sesją strona, na której klienci wybierają produkty do zwrotu i podają numer konta bankowego. Wymaga aktywnej sesji lub tokenu weryfikacyjnego.','Confirmation page shown after a successful return submission. Displays order summary and the company address where the package should be sent. Configure company address in the Return Confirmation tab.'=>'Strona potwierdzenia wyświetlana po pomyślnym złożeniu zwrotu. Pokazuje podsumowanie zamówienia oraz adres firmy, na który należy nadać paczkę. Adres firmy skonfiguruj w zakładce Potwierdzenia Zwrotu.','Download PDF'=>'Pobierz PDF','Mark as completed'=>'Oznacz jako zrealizowany','Mark as issue'=>'Zgłoś problem','Note:'=>'Uwaga:','The overall layout and styling of these emails are natively managed by WooCommerce to match your store\'s theme. You only control the text contents here.'=>'Ogólny wygląd i stylowanie tych e-maili są natywnie zarządzane przez WooCommerce, aby dopasować motyw Twojego sklepu. Tutaj kontrolujesz tylko treść wiadomości.','Law Compliance'=>'Zgodność z prawem','Compliance Region:'=>'Region prawny:','EU + EEA'=>'UE + EOG','Poland'=>'Polska','United Kingdom'=>'Wielka Brytania','Switzerland'=>'Szwajcaria','Turkey'=>'Turcja','Ukraine / Moldova'=>'Ukraina / Mołdawia','USA'=>'USA','Canada'=>'Kanada','Australia / New Zealand'=>'Australia / Nowa Zelandia','Brazil'=>'Brazylia','Custom'=>'Niestandardowy','Select the appropriate legal framework for the return disclaimer. Based on your selection, specific regulations and return time windows will be shown to users.'=>'Wybierz odpowiednie ramy prawne dla zastrzeżeń dotyczących zwrotów. Na podstawie Twojego wyboru użytkownikom będą wyświetlane konkretne przepisy i okna czasowe zwrotów.','Custom Disclaimer:'=>'Niestandardowe zastrzeżenie:','Enter your custom legal disclaimer. HTML tags are allowed.'=>'Wpisz własną klauzulę prawną. Dozwolone są tagi HTML.','Is your store compliant with GDPR regulations?'=>'Czy Twój sklep jest zgodny z przepisami RODO?','If checked, the return form will explicitly state that personal data processing complies with GDPR regulations.'=>'Jeśli zaznaczono, formularz zwrotu będzie wyraźnie informował, że przetwarzanie danych osobowych odbywa się zgodnie z przepisami RODO.','Save compliance settings'=>'Zapisz ustawienia zgodności','Law compliance settings saved.'=>'Ustawienia zgodności z prawem zostały zapisane.','1. Configuration and Initialization'=>'1. Konfiguracja i inicjalizacja','System Status'=>'Status systemu','You can disable the system using the toggle in the Information tab while you configure the plugin, and re-enable it when you are ready to launch.'=>'Możesz wyłączyć system za pomocą przełącznika w zakładce Informacje podczas konfiguracji wtyczki i ponownie go włączyć, gdy będziesz gotowy do uruchomienia.','Automated Pages'=>'Automatyczne strony','By clicking "Check and Create Required Pages" in the Pages tab, three routing pages are automatically created using shortcodes (Return Form, Select Return Items, Return Confirmation).'=>'Po kliknięciu opcji "Sprawdź i utwórz wymagane strony" w zakładce Strony, automatycznie tworzone są trzy strony routingowe ze shortcode\'ami (Formularz zwrotu, Wybierz przedmioty do zwrotu, Potwierdzenie zwrotu).','Tip: These automatically created pages are fully customizable. The generated shortcode must remain on the page, but you can add your own content below or above it as needed.'=>'Wskazówka: Te automatycznie tworzone strony są w pełni konfigurowalne. Wygenerowany shortcode musi pozostać na stronie, ale możesz dodawać własną treść powyżej lub poniżej, zgodnie z potrzebami.','In the Law Compliance tab, you can select your store\'s legal region to automatically display the correct consumer protection act disclaimer during the return process. You can also write your own custom legal disclaimer.'=>'W zakładce Zgodność z prawem możesz wybrać region prawny swojego sklepu, aby automatycznie wyświetlać właściwą klauzulę prawną dotyczącą ochrony konsumentów podczas procesu zwrotu. Możesz też wpisać własne niestandardowe zastrzeżenie prawne.','Localization & Translation'=>'Lokalizacja i tłumaczenia','This plugin is fully translatable on both the frontend and backend. English is the default base language, but Polish (pl_PL) is 100% pre-built out-of-the-box. The plugin automatically grabs your active WordPress language setting to display the proper language if translations exist. Missing translations can be easily added using standard translation plugins like Open World or Loco Translate.'=>'Ta wtyczka jest w pełni przetłumaczalna zarówno na frontendie, jak i backendzie. Angielski jest domyślnym językiem bazowym, ale polski (pl_PL) jest w 100% dostępny od razu po instalacji. Wtyczka automatycznie pobiera aktywne ustawienie języka WordPress, aby wyświetlić właściwy język, jeśli tłumaczenia istnieją. Brakujące tłumaczenia można łatwo dodać za pomocą standardowych wtyczek do tłumaczeń, takich jak Open World lub Loco Translate.','6. Return Status Management and Order Integration'=>'6. Zarządzanie statusem zwrotu i integracja z zamówieniami','Return List Backend:'=>'Lista zwrotów (backend):','All returns arrive with a "Pending" status in the main plugin table. Administrators can use quick action buttons to mark a return as "Completed" or flag it as an "Issue".'=>'Wszystkie zwroty trafiają ze statusem "Oczekujący" do głównej tabeli wtyczki. Administratorzy mogą używać przycisków szybkich akcji, aby oznaczyć zwrot jako "Zrealizowany" lub zgłosić go jako "Problem".','WooCommerce Order Meta Box:'=>'Meta Box zamówienia WooCommerce:','When viewing a specific order from the WooCommerce interface, a dedicated Meta Box will surface the associated Return. Store owners can alter the status from here natively.'=>'Podczas przeglądania konkretnego zamówienia w interfejsie WooCommerce, dedykowany Meta Box wyświetli powiązany zwrot. Właściciele sklepów mogą natywnie zmieniać status bezpośrednio stąd.','Issue Resolution Notes:'=>'Notatki dotyczące rozwiązania problemu:','If a return is flagged as an "Issue" through the Order Meta Box, an optional explanation box appears. Submitting an explanation dynamically saves it as a Customer Order Note, updating the buyer automatically via WooCommerce\'s built-in email alerts.'=>'Jeśli zwrot zostanie oznaczony jako "Problem" przez Meta Box zamówienia, pojawia się opcjonalne pole wyjaśnienia. Przesłanie wyjaśnienia dynamicznie zapisuje je jako Notatkę w Zamówieniu Klienta, automatycznie aktualizując kupującego za pomocą wbudowanych alertów e-mail WooCommerce.','Completed'=>'Zrealizowany','Issue'=>'Problem','Pending'=>'Oczekujący','Delete'=>'Usuń','Are you sure you want to permanently delete this return record? This action cannot be undone.'=>'Czy na pewno chcesz trwale usunąć ten rekord zwrotu? Tej operacji nie można cofnąć.']];